<script setup lang="ts">
const svc=useAttendanceShifts(); const workspace=useWorkspace(); const feedback=useUiFeedback(); const loading=ref(false); const policies=ref<any[]>([]); const form=ref<any>({name:'Default Attendance Policy',graceMinutes:10,lateAfterMinutes:10,halfDayAfterMinutes:750,minimumFullDayMinutes:480,minimumHalfDayMinutes:240,overtimeAfterMinutes:540,duplicateWindowMinutes:5,active:true})
async function refresh(){ loading.value=true; try{ policies.value=await svc.policies() }catch(e:any){ feedback.fromError('Policies refresh failed',e) } finally{ loading.value=false } }
async function save(){ await svc.createPolicy({...form.value, companyId:workspace.companyId.value, storeGroupId:workspace.storeGroupId.value, storeId:workspace.storeId.value}); await refresh() }
onMounted(refresh)
</script>
<template><AppShell title="Attendance Policy" @refresh="refresh"><section class="space-y-5"><UiModulePageHeader title="Attendance Policy" description="Grace, duplicate prevention, half-day and overtime rule settings." icon="i-lucide-sliders-horizontal"><template #actions><UButton label="Refresh" :loading="loading" @click="refresh"/></template></UiModulePageHeader><UCard><AttendancePolicyForm v-model="form"/><UButton class="mt-3" label="Add Policy" @click="save"/></UCard><div class="grid gap-3 md:grid-cols-2"><UCard v-for="row in policies" :key="row.id"><strong>{{ row.name }}</strong><p class="text-xs text-muted">Grace {{ row.graceMinutes }}m · Duplicate window {{ row.duplicateWindowMinutes }}m · Active {{ row.active }}</p></UCard></div></section></AppShell></template>
